import React, { useState } from 'react';
import axios from 'axios';
import { MapContainer, TileLayer, Marker, Popup } from 'react-leaflet';
import L from 'leaflet';
import 'leaflet/dist/leaflet.css';

// Fix for Leaflet marker icons not showing up in React
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon-2x.png',
  iconUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon.png',
  shadowUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-shadow.png',
});

function App() {
  const [medicine, setMedicine] = useState('');
  const [pharmacies, setPharmacies] = useState([]);
  const calculateDistance = (lat1, lon1, lat2, lon2) => {
  const R = 6371; // Radius of the earth in km
  const dLat = (lat2 - lat1) * (Math.PI / 180);
  const dLon = (lon2 - lon1) * (Math.PI / 180);
  const a = 
    Math.sin(dLat / 2) * Math.sin(dLat / 2) +
    Math.cos(lat1 * (Math.PI / 180)) * Math.cos(lat2 * (Math.PI / 180)) * Math.sin(dLon / 2) * Math.sin(dLon / 2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return (R * c).toFixed(1); // Returns distance rounded to 1 decimal
};

  const handleSearch = () => {
  // 1. Full database of markers for the demo
  const allData = [
    // --- INSULIN / DIABETES ---
    { id: 1, name: "Apollo Pharmacy", med: "Insulin", pos: [12.9716, 77.5946], area: "MG Road" },
    { id: 2, name: "MedPlus", med: "Insulin", pos: [12.9250, 77.5824], area: "Jayanagar" },

    // --- CARDIAC / HEART (ECOSPRIN) ---
    { id: 3, name: "Trust Chemist", med: "Ecosprin", pos: [12.9784, 77.6413], area: "Indiranagar" },
    { id: 4, name: "Aster Pharmacy", med: "Ecosprin", pos: [13.0285, 77.5900], area: "Hebbal" },

    // --- PAIN RELIEF / FEVER (DOLO 650) ---
    { id: 5, name: "Noble Plus", med: "Dolo 650", pos: [12.9352, 77.6245], area: "Koramangala" },
    { id: 6, name: "Wellness Forever", med: "Dolo 650", pos: [12.9698, 77.7499], area: "Whitefield" },

    // --- ASTHMA (INHALERS) ---
    { id: 7, name: "LifeCare", med: "Inhaler", pos: [12.9141, 77.6411], area: "HSR Layout" },
    { id: 8, name: "Generic Aadhaar", med: "Inhaler", pos: [13.0067, 77.5300], area: "Rajajinagar" }
  ];

  // 2. Filter logic based on what YOU type in the search bar
  const filtered = allData.filter(item => 
    item.med.toLowerCase().includes(medicine.toLowerCase())
  );

  // 3. Update the map pins
  setPharmacies(filtered.map(item => ({
    id: item.id,
    name: item.name,
    medicine_name: item.med,
    location: { coordinates: [item.pos[1], item.pos[0]] } // Note: Leaflet uses [Lat, Lng]
  })));
};

  return (
    <div style={{ padding: '20px', fontFamily: 'Arial, sans-serif' }}>
      <h1 style={{ color: '#e74c3c' }}>🚑 MedQuick SOS</h1>

      <div style={{ marginBottom: '20px' }}>
        <input 
          placeholder="Enter medicine name (e.g., Insulin)..." 
          onChange={(e) => setMedicine(e.target.value)}
          style={{ padding: '10px', width: '300px', borderRadius: '5px', border: '1px solid #ccc' }}
        />
        <button 
          onClick={handleSearch} 
          style={{ 
            padding: '10px 20px', 
            backgroundColor: '#e74c3c', 
            color: 'white', 
            border: 'none', 
            marginLeft: '10px', 
            cursor: 'pointer',
            borderRadius: '5px'
          }}
        >
          FIND PHARMACY
        </button>
      </div>

      <MapContainer 
        center={[12.9716, 77.5946]} 
        zoom={13} 
        style={{ height: "500px", width: "100%", borderRadius: "10px", border: '2px solid #ddd' }}
      >
        <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />

        {pharmacies.map((p) => (
  <Marker key={p.id} position={[p.location.coordinates[1], p.location.coordinates[0]]}>
    <Popup style={{ borderRadius: '10px' }}>
      <div style={{ textAlign: 'center' }}>
        <h3 style={{ margin: '0', color: '#e74c3c' }}>{p.name}</h3>
        <hr />
        <p><b>Medicine:</b> {p.medicine_name}</p>
        <p style={{ color: 'green' }}>● In Stock (Verified)</p>
        <button style={{ background: '#3498db', color: 'white', border: 'none', padding: '5px', borderRadius: '3px' }}>
          Get Directions
        </button>
      </div>
    </Popup>
  </Marker>
))}
      </MapContainer>
    </div>
  );
}

export default App;
